namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9]+$", ErrorMessage = "Student ID must be alphanumeric.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS" },
        new() { Id = 2, Name = "Mathematics", Code = "MATH" },
        new() { Id = 3, Name = "Physics", Code = "PHYS" },
        new() { Id = 4, Name = "English", Code = "ENG" },
        new() { Id = 5, Name = "History", Code = "HIST" },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, data structures, and object-oriented principles.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of industry experience and specializes in software engineering education.", DepartmentId = 1, IsFeatured = true },
        new() { Id = 2, CourseCode = "CS 201", Title = "Data Structures & Algorithms", Description = "A deep dive into fundamental data structures (arrays, trees, graphs, hash tables) and algorithm design techniques.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park's research focuses on algorithm optimization and competitive programming pedagogy.", DepartmentId = 1, IsFeatured = false },
        new() { Id = 3, CourseCode = "CS 350", Title = "Database Systems", Description = "Relational database design, SQL, normalization, transactions, and an introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Prof. Maria Lopez", InstructorBio = "Prof. Lopez previously worked as a database architect at a Fortune 500 company.", DepartmentId = 1, IsFeatured = true },
        new() { Id = 4, CourseCode = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator with publications in mathematical analysis.", DepartmentId = 2, IsFeatured = false },
        new() { Id = 5, CourseCode = "MATH 210", Title = "Linear Algebra", Description = "Vector spaces, matrices, eigenvalues, and linear transformations.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Emily Zhao", InstructorBio = "Dr. Zhao's research spans applied linear algebra and machine learning theory.", DepartmentId = 2, IsFeatured = true },
        new() { Id = 6, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:00 PM", InstructorName = "Dr. Alan Patel", InstructorBio = "Dr. Patel is an experimental physicist with expertise in optics and photonics.", DepartmentId = 3, IsFeatured = false },
        new() { Id = 7, CourseCode = "PHYS 220", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Lisa Nakamura", InstructorBio = "Dr. Nakamura researches plasma physics and teaches graduate-level electrodynamics.", DepartmentId = 3, IsFeatured = true },
        new() { Id = 8, CourseCode = "ENG 101", Title = "Composition & Rhetoric", Description = "Develop college-level writing skills through essays, research papers, and peer review.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", InstructorName = "Prof. David Wright", InstructorBio = "Prof. Wright is a published author who brings creative writing expertise to academic composition.", DepartmentId = 4, IsFeatured = false },
        new() { Id = 9, CourseCode = "ENG 250", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", InstructorName = "Dr. Angela Morrison", InstructorBio = "Dr. Morrison specializes in 20th-century American fiction and literary criticism.", DepartmentId = 4, IsFeatured = false },
        new() { Id = 10, CourseCode = "HIST 101", Title = "World History to 1500", Description = "A global survey of human civilizations from antiquity through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Thomas Grant", InstructorBio = "Dr. Grant is an archaeologist-turned-historian with fieldwork experience across three continents.", DepartmentId = 5, IsFeatured = true },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);
}

